   // \u521b\u5efa\u4e00\u4e2a\u70b9\u51fb\u4e8b\u4ef6\\n    const event = new MouseEvent(\'click\');\\n    // \u5c06 a \u7684 download \u5c5e\u6027\u8bbe\u7f6e\u4e3a\u6211\u4eec\u60f3\u8981\u4e0b\u8f7d\u7684\u56fe\u7247\u7684\u540d\u79f0\uff0c\u82e5 name \u4e0d\u5b58\u5728\u5219\u4f7f\u7528\'\u56fe\u7247\'\u4f5c\u4e3a\u9ed8\u8ba4\u540d\u79f0\\n    a.download = name || \'\u56fe\u7247\';\\n    // \u5c06\u751f\u6210\u7684 URL \u8bbe\u7f6e\u4e3a a.href \u5c5e\u6027\\n    a.href = url;\\n    // \u89e6\u53d1 a \u7684\u70b9\u51fb\u4e8b\u4ef6\\n    a.dispatchEvent(event);\\n    // return a;\\n  };\\n  image.src = document.getElementById(selector)?.src ?? \'\';\\n};\\n```"},{"id":"svg-to-react-component","metadata":{"permalink":"/blog/svg-to-react-component","source":"@site/blog/2024-02-10-svg\u8f6creact\u7ec4\u4ef6.md","title":"SVG \u8f6c React \u7ec4\u4ef6","description":"\u5c06SVG\u6587\u4ef6\u8f6c\u4e3aReact\u7ec4\u4ef6","date":"2024-02-10T00:00:00.000Z","tags":[{"inline":true,"label":"svg","permalink":"/blog/tags/svg"},{"inline":true,"label":"react","permalink":"/blog/tags/react"}],"readingTime":0.28,"hasTruncateMarker":true,"authors":[{"name":"zpcscc","url":"https://github.com/zpcscc","title":"\u524d\u7aef\u5f00\u53d1\u8005","key":"zpcscc","page":null}],"frontMatter":{"title":"SVG \u8f6c React \u7ec4\u4ef6","slug":"svg-to-react-component","authors":["zpcscc"],"tags":["svg","react"]},"unlisted":false,"prevItem":{"title":"\u524d\u7aef\u4e0b\u8f7d\u56fe\u7247","permalink":"/blog/frontend-download-image"},"nextItem":{"title":"Ajax Error \u5904\u7406","permalink":"/blog/ajax-error-handling"}},"content":"## \u5c06SVG\u6587\u4ef6\u8f6c\u4e3aReact\u7ec4\u4ef6\\n\\n\x3c!-- truncate --\x3e\\n### 1\u3001\u51c6\u5907\u597dsvg\u683c\u5f0f\u6587\u4ef6\\n\\n### 2\u3001\u5728\u6b64\u6587\u4ef6\u7684\u6587\u4ef6\u5939\u4e0b\uff0c\u8fd0\u884c\u4ee5\u4e0b\u547d\u4ee4\\n\\n```typescript\\nnpx @svgr/cli --icon icon.svg\\n```\\n\\n### 3\u3001\u8f6c\u6362\u6210\u529f\u540e\uff0c\u4f1a\u5728